namespace sv_836b8e79e3414553ad7d71eaac6c9c4a.Services;

/// <summary>
/// Scoped per circuit — each user session gets its own instance,
/// so one manager's selection never leaks to another.
/// </summary>
public sealed class WarehouseState
{
    public static readonly IReadOnlyList<(string Id, string Name)> AvailableWarehouses =
    [
        ("WH-001", "Warehouse A — Main Distribution"),
        ("WH-002", "Warehouse B — East Regional"),
        ("WH-003", "Warehouse C — West Regional"),
        ("WH-004", "Warehouse D — Cold Storage"),
    ];

    private string _currentWarehouseId = AvailableWarehouses[0].Id;

    public string CurrentWarehouseId => _currentWarehouseId;

    public string CurrentWarehouseName =>
        AvailableWarehouses.First(w => w.Id == _currentWarehouseId).Name;

    public event Action? OnChange;

    public void SetWarehouse(string warehouseId)
    {
        if (_currentWarehouseId == warehouseId) return;

        _currentWarehouseId = warehouseId;
        OnChange?.Invoke();
    }
}

namespace sv_836b8e79e3414553ad7d71eaac6c9c4a.Services;

/// <summary>
/// Scoped per circuit. Simulates a database query for low-stock items
/// and exposes a polling mechanism that notifies all subscribers.
/// </summary>
public sealed class InventoryAlertService : IDisposable
{
    private readonly WarehouseState _warehouseState;
    private readonly Random _random = new();
    private PeriodicTimer? _timer;
    private CancellationTokenSource? _cts;
    private int _activeConsumers;

    public InventoryAlertService(WarehouseState warehouseState)
    {
        _warehouseState = warehouseState;
    }

    public int LowStockCount { get; private set; }

    /// <summary>
    /// Fired on the polling thread whenever new data arrives.
    /// Subscribers must marshal to the UI thread (InvokeAsync) themselves.
    /// </summary>
    public event Action? OnAlertUpdated;

    /// <summary>Simulates a DB query — returns a random number 0‒15.</summary>
    public Task<int> GetLowStockCountAsync(string warehouseId)
    {
        return Task.FromResult(_random.Next(0, 16));
    }

    /// <summary>
    /// Reference-counted start: the first caller spins up the timer;
    /// subsequent callers just bump the count.
    /// </summary>
    public void StartPolling()
    {
        _activeConsumers++;
        if (_activeConsumers > 1) return;

        _cts = new CancellationTokenSource();
        _timer = new PeriodicTimer(TimeSpan.FromSeconds(10));
        _ = PollLoopAsync(_cts.Token);
    }

    /// <summary>
    /// Reference-counted stop: polling only halts when every consumer
    /// has called StopPolling.
    /// </summary>
    public void StopPolling()
    {
        _activeConsumers = Math.Max(0, _activeConsumers - 1);
        if (_activeConsumers > 0) return;

        _cts?.Cancel();
        _timer?.Dispose();
        _timer = null;
    }

    /// <summary>Fetch immediately (e.g. on warehouse change) and notify.</summary>
    public async Task RefreshAsync()
    {
        LowStockCount = await GetLowStockCountAsync(_warehouseState.CurrentWarehouseId);
        OnAlertUpdated?.Invoke();
    }

    private async Task PollLoopAsync(CancellationToken ct)
    {
        // Fire once immediately so the UI isn't empty for 10 seconds.
        await RefreshAsync();

        while (!ct.IsCancellationRequested)
        {
            try
            {
                if (_timer is null || !await _timer.WaitForNextTickAsync(ct))
                    break;

                await RefreshAsync();
            }
            catch (OperationCanceledException)
            {
                break;
            }
        }
    }

    public void Dispose()
    {
        _cts?.Cancel();
        _timer?.Dispose();
    }
}

@rendermode InteractiveServer
@using sv_836b8e79e3414553ad7d71eaac6c9c4a.Services
@inject WarehouseState WarehouseState

<div class="warehouse-selector">
    <label class="form-label text-white mb-1 small">Current Warehouse</label>
    <select class="form-select form-select-sm"
            value="@WarehouseState.CurrentWarehouseId"
            @onchange="OnWarehouseChanged">
        @foreach (var (id, name) in WarehouseState.AvailableWarehouses)
        {
            <option value="@id">@name</option>
        }
    </select>
</div>

@code {
    private void OnWarehouseChanged(ChangeEventArgs e)
    {
        var newId = e.Value?.ToString();
        if (!string.IsNullOrEmpty(newId))
        {
            WarehouseState.SetWarehouse(newId);
        }
    }
}

@rendermode InteractiveServer
@implements IDisposable
@using sv_836b8e79e3414553ad7d71eaac6c9c4a.Services
@inject InventoryAlertService AlertService

<span class="badge rounded-pill @BadgeClass">@AlertService.LowStockCount</span>

@code {
    private string BadgeClass => AlertService.LowStockCount switch
    {
        0 => "bg-success",
        <= 5 => "bg-warning text-dark",
        _ => "bg-danger"
    };

    protected override void OnInitialized()
    {
        AlertService.OnAlertUpdated += HandleAlertUpdated;
    }

    private void HandleAlertUpdated()
    {
        InvokeAsync(StateHasChanged);
    }

    public void Dispose()
    {
        AlertService.OnAlertUpdated -= HandleAlertUpdated;
    }
}

@page "/dashboard"
@rendermode InteractiveServer
@implements IDisposable
@using sv_836b8e79e3414553ad7d71eaac6c9c4a.Services
@inject WarehouseState WarehouseState
@inject InventoryAlertService AlertService

<PageTitle>Dashboard — @WarehouseState.CurrentWarehouseName</PageTitle>

<h1>Warehouse Dashboard</h1>

<div class="card mb-4">
    <div class="card-body">
        <h5 class="card-title">@WarehouseState.CurrentWarehouseName</h5>
        <p class="card-text text-muted">ID: @WarehouseState.CurrentWarehouseId</p>
    </div>
</div>

<div class="row g-4">
    <div class="col-md-4">
        <div class="card text-white @AlertCardClass">
            <div class="card-body text-center">
                <h2 class="display-4">@AlertService.LowStockCount</h2>
                <p class="card-text">Low-Stock Alerts</p>
            </div>
        </div>
    </div>

    <div class="col-md-4">
        <div class="card border-primary">
            <div class="card-body text-center">
                <h2 class="display-4 text-primary">@(_totalItems)</h2>
                <p class="card-text text-muted">Total SKUs Tracked</p>
            </div>
        </div>
    </div>

    <div class="col-md-4">
        <div class="card border-info">
            <div class="card-body text-center">
                <h2 class="display-4 text-info">@(_lastRefreshed?.ToString("HH:mm:ss") ?? "—")</h2>
                <p class="card-text text-muted">Last Refreshed</p>
            </div>
        </div>
    </div>
</div>

<p class="text-muted mt-3">
    <em>Polling every 10 seconds. Alert count is a simulated random value (0–15).</em>
</p>

@code {
    private int _totalItems = 1_247;
    private DateTime? _lastRefreshed;

    private string AlertCardClass => AlertService.LowStockCount switch
    {
        0 => "bg-success",
        <= 5 => "bg-warning text-dark",
        _ => "bg-danger"
    };

    protected override void OnInitialized()
    {
        WarehouseState.OnChange += HandleWarehouseChanged;
        AlertService.OnAlertUpdated += HandleAlertUpdated;
        AlertService.StartPolling();
    }

    private void HandleWarehouseChanged()
    {
        // Warehouse changed — fetch fresh data immediately.
        InvokeAsync(async () =>
        {
            await AlertService.RefreshAsync();
            StateHasChanged();
        });
    }

    private void HandleAlertUpdated()
    {
        _lastRefreshed = DateTime.Now;
        InvokeAsync(StateHasChanged);
    }

    public void Dispose()
    {
        WarehouseState.OnChange -= HandleWarehouseChanged;
        AlertService.OnAlertUpdated -= HandleAlertUpdated;
        AlertService.StopPolling();
    }
}

