@page "/dashboard"
@rendermode InteractiveServer
@implements IDisposable
@using sv_836b8e79e3414553ad7d71eaac6c9c4a.Services
@inject WarehouseState WarehouseState
@inject InventoryAlertService AlertService

<PageTitle>Dashboard — @WarehouseState.CurrentWarehouseName</PageTitle>

<h1>Warehouse Dashboard</h1>

<div class="card mb-4">
    <div class="card-body">
        <h5 class="card-title">@WarehouseState.CurrentWarehouseName</h5>
        <p class="card-text text-muted">ID: @WarehouseState.CurrentWarehouseId</p>
    </div>
</div>

<div class="row g-4">
    <div class="col-md-4">
        <div class="card text-white @AlertCardClass">
            <div class="card-body text-center">
                <h2 class="display-4">@AlertService.LowStockCount</h2>
                <p class="card-text">Low-Stock Alerts</p>
            </div>
        </div>
    </div>

    <div class="col-md-4">
        <div class="card border-primary">
            <div class="card-body text-center">
                <h2 class="display-4 text-primary">@(_totalItems)</h2>
                <p class="card-text text-muted">Total SKUs Tracked</p>
            </div>
        </div>
    </div>

    <div class="col-md-4">
        <div class="card border-info">
            <div class="card-body text-center">
                <h2 class="display-4 text-info">@(_lastRefreshed?.ToString("HH:mm:ss") ?? "—")</h2>
                <p class="card-text text-muted">Last Refreshed</p>
            </div>
        </div>
    </div>
</div>

<p class="text-muted mt-3">
    <em>Polling every 10 seconds. Alert count is a simulated random value (0–15).</em>
</p>

@code {
    private int _totalItems = 1_247;
    private DateTime? _lastRefreshed;

    private string AlertCardClass => AlertService.LowStockCount switch
    {
        0 => "bg-success",
        <= 5 => "bg-warning text-dark",
        _ => "bg-danger"
    };

    protected override void OnInitialized()
    {
        WarehouseState.OnChange += HandleWarehouseChanged;
        AlertService.OnAlertUpdated += HandleAlertUpdated;
        AlertService.StartPolling();
    }

    private void HandleWarehouseChanged()
    {
        // Warehouse changed — fetch fresh data immediately.
        InvokeAsync(async () =>
        {
            await AlertService.RefreshAsync();
            StateHasChanged();
        });
    }

    private void HandleAlertUpdated()
    {
        _lastRefreshed = DateTime.Now;
        InvokeAsync(StateHasChanged);
    }

    public void Dispose()
    {
        WarehouseState.OnChange -= HandleWarehouseChanged;
        AlertService.OnAlertUpdated -= HandleAlertUpdated;
        AlertService.StopPolling();
    }
}

